        L = torch.cholesky(K)
        return -0.5 * (y_train.T @ torch.cholesky_solve(y_train, L) + L.diag().log().sum() + len(x_train) * np.log(2 * np.pi))
    elif Kinv_method == 'direct':
        K_inv = torch.inverse(K)
